const double Rt_22_t4 = igt00*(C2_002*C1_200 + C2_002*C1_200 + C2_020*C1_002) + igt01*(C2_002*C1_201 + C2_002*C1_201 + C2_021*C1_002) + igt02*(C2_002*C1_202 + C2_002*C1_202 + C2_022*C1_002) + igt10*(C2_012*C1_200 + C2_012*C1_200 + C2_020*C1_012) + igt11*(C2_012*C1_201 + C2_012*C1_201 + C2_021*C1_012) + igt12*(C2_012*C1_202 + C2_012*C1_202 + C2_022*C1_012) + igt20*(C2_022*C1_200 + C2_022*C1_200 + C2_020*C1_022) + igt21*(C2_022*C1_201 + C2_022*C1_201 + C2_021*C1_022) + igt22*(C2_022*C1_202 + C2_022*C1_202 + C2_022*C1_022) + igt00*(C2_102*C1_210 + C2_102*C1_210 + C2_120*C1_102) + igt01*(C2_102*C1_211 + C2_102*C1_211 + C2_121*C1_102) + igt02*(C2_102*C1_212 + C2_102*C1_212 + C2_122*C1_102) + igt10*(C2_112*C1_210 + C2_112*C1_210 + C2_120*C1_112) + igt11*(C2_112*C1_211 + C2_112*C1_211 + C2_121*C1_112) + igt12*(C2_112*C1_212 + C2_112*C1_212 + C2_122*C1_112) + igt20*(C2_122*C1_210 + C2_122*C1_210 + C2_120*C1_122) + igt21*(C2_122*C1_211 + C2_122*C1_211 + C2_121*C1_122) + igt22*(C2_122*C1_212 + C2_122*C1_212 + C2_122*C1_122) + igt00*(C2_202*C1_220 + C2_202*C1_220 + C2_220*C1_202) + igt01*(C2_202*C1_221 + C2_202*C1_221 + C2_221*C1_202) + igt02*(C2_202*C1_222 + C2_202*C1_222 + C2_222*C1_202) + igt10*(C2_212*C1_220 + C2_212*C1_220 + C2_220*C1_212) + igt11*(C2_212*C1_221 + C2_212*C1_221 + C2_221*C1_212) + igt12*(C2_212*C1_222 + C2_212*C1_222 + C2_222*C1_212) + igt20*(C2_222*C1_220 + C2_222*C1_220 + C2_220*C1_222) + igt21*(C2_222*C1_221 + C2_222*C1_221 + C2_221*C1_222) + igt22*(C2_222*C1_222 + C2_222*C1_222 + C2_222*C1_222);
const double Rt_22 = Rt_22_t1 + Rt_22_t2 + Rt_22_t3 + Rt_22_t4;

// Rphi
const double C2_dc00 = C2_000*d_ch0 + C2_100*d_ch1 + C2_200*d_ch2;
const double C2_dc01 = C2_010*d_ch0 + C2_110*d_ch1 + C2_210*d_ch2;
const double C2_dc02 = C2_020*d_ch0 + C2_120*d_ch1 + C2_220*d_ch2;
const double C2_dc10 = C2_001*d_ch0 + C2_101*d_ch1 + C2_201*d_ch2;
const double C2_dc11 = C2_011*d_ch0 + C2_111*d_ch1 + C2_211*d_ch2;
const double C2_dc12 = C2_021*d_ch0 + C2_121*d_ch1 + C2_221*d_ch2;
const double C2_dc20 = C2_002*d_ch0 + C2_102*d_ch1 + C2_202*d_ch2;
const double C2_dc21 = C2_012*d_ch0 + C2_112*d_ch1 + C2_212*d_ch2;
const double C2_dc22 = C2_022*d_ch0 + C2_122*d_ch1 + C2_222*d_ch2;
const double xRphi00 = 0.5*chi_inv*(d2_ch00 - C2_dc00) - 0.25*chi_inv*chi_inv*d_ch0*d_ch0;
const double xRphi01 = 0.5*chi_inv*(d2_ch01 - C2_dc01) - 0.25*chi_inv*chi_inv*d_ch0*d_ch1;
const double xRphi02 = 0.5*chi_inv*(d2_ch02 - C2_dc02) - 0.25*chi_inv*chi_inv*d_ch0*d_ch2;
const double xRphi10 = 0.5*chi_inv*(d2_ch10 - C2_dc10) - 0.25*chi_inv*chi_inv*d_ch1*d_ch0;
const double xRphi11 = 0.5*chi_inv*(d2_ch11 - C2_dc11) - 0.25*chi_inv*chi_inv*d_ch1*d_ch1;
const double xRphi12 = 0.5*chi_inv*(d2_ch12 - C2_dc12) - 0.25*chi_inv*chi_inv*d_ch1*d_ch2;
const double xRphi20 = 0.5*chi_inv*(d2_ch20 - C2_dc20) - 0.25*chi_inv*chi_inv*d_ch2*d_ch0;
const double xRphi21 = 0.5*chi_inv*(d2_ch21 - C2_dc21) - 0.25*chi_inv*chi_inv*d_ch2*d_ch1;
const double xRphi22 = 0.5*chi_inv*(d2_ch22 - C2_dc22) - 0.25*chi_inv*chi_inv*d_ch2*d_ch2;
const double igt_d2chi = igt00*d2_ch00 + igt01*d2_ch01 + igt02*d2_ch02 + igt10*d2_ch10 + igt11*d2_ch11 + igt12*d2_ch12 + igt20*d2_ch20 + igt21*d2_ch21 + igt22*d2_ch22;
const double igt_dchi_dchi = igt00*d_ch0*d_ch0 + igt01*d_ch0*d_ch1 + igt02*d_ch0*d_ch2 + igt10*d_ch1*d_ch0 + igt11*d_ch1*d_ch1 + igt12*d_ch1*d_ch2 + igt20*d_ch2*d_ch0 + igt21*d_ch2*d_ch1 + igt22*d_ch2*d_ch2;
const double CalGt_dchi = CalGt0*d_ch0 + CalGt1*d_ch1 + CalGt2*d_ch2;
const double scalar_part = igt_d2chi - 1.5*chi_inv*igt_dchi_dchi - CalGt_dchi;

const double R00 = Rt_00 + xRphi00 + 0.5*chi_inv*gt00*scalar_part;
const double R01 = Rt_01 + xRphi01 + 0.5*chi_inv*gt01*scalar_part;
const double R02 = Rt_02 + xRphi02 + 0.5*chi_inv*gt02*scalar_part;
const double R10 = Rt_10 + xRphi10 + 0.5*chi_inv*gt10*scalar_part;
const double R11 = Rt_11 + xRphi11 + 0.5*chi_inv*gt11*scalar_part;
const double R12 = Rt_12 + xRphi12 + 0.5*chi_inv*gt12*scalar_part;
const double R20 = Rt_20 + xRphi20 + 0.5*chi_inv*gt20*scalar_part;
const double R21 = Rt_21 + xRphi21 + 0.5*chi_inv*gt21*scalar_part;
const double R22 = Rt_22 + xRphi22 + 0.5*chi_inv*gt22*scalar_part;

// === L6: Derived quantities ===
const double At_UU00 = igt00*igt00*At00 + igt00*igt01*At01 + igt00*igt02*At02 + igt01*igt00*At10 + igt01*igt01*At11 + igt01*igt02*At12 + igt02*igt00*At20 + igt02*igt01*At21 + igt02*igt02*At22;
