const double At_UU22 = igt20*igt20*At00 + igt20*igt21*At01 + igt20*igt22*At02 + igt21*igt20*At10 + igt21*igt21*At11 + igt21*igt22*At12 + igt22*igt20*At20 + igt22*igt21*At21 + igt22*igt22*At22;
