const double AikAkj11 = At10*A_ud01 + At11*A_ud11 + At12*A_ud21;
const double AikAkj12 = At10*A_ud02 + At11*A_ud12 + At12*A_ud22;
const double AikAkj21 = AikAkj12;
const double AikAkj22 = At20*A_ud02 + At21*A_ud12 + At22*A_ud22;
const double DiDj_a00 = d2_al00 - (C3_000*d_al0 + C3_100*d_al1 + C3_200*d_al2);
