const double trace_val = igt00*(al*R00 - DiDj_a00) + igt01*(al*R01 - DiDj_a01) + igt02*(al*R02 - DiDj_a02) + igt10*(al*R10 - DiDj_a10) + igt11*(al*R11 - DiDj_a11) + igt12*(al*R12 - DiDj_a12) + igt20*(al*R20 - DiDj_a20) + igt21*(al*R21 - DiDj_a21) + igt22*(al*R22 - DiDj_a22);
const double tf00 = (al*R00 - DiDj_a00) - gt00*trace_val/3.0;
const double tf01 = (al*R01 - DiDj_a01) - gt01*trace_val/3.0;
