const double tf22 = (al*R22 - DiDj_a22) - gt22*trace_val/3.0;
const double At_sqr = At00*At_UU00 + At01*At_UU01 + At02*At_UU02 + At10*At_UU10 + At11*At_UU11 + At12*At_UU12 + At20*At_UU20 + At21*At_UU21 + At22*At_UU22;
const double lap_a = ch*igt00*(d2_al00 - (C3_000*d_al0 + C3_100*d_al1 + C3_200*d_al2)) + ch*igt01*(d2_al01 - (C3_001*d_al0 + C3_101*d_al1 + C3_201*d_al2)) + ch*igt02*(d2_al02 - (C3_002*d_al0 + C3_102*d_al1 + C3_202*d_al2)) + ch*igt10*(d2_al10 - (C3_010*d_al0 + C3_110*d_al1 + C3_210*d_al2)) + ch*igt11*(d2_al11 - (C3_011*d_al0 + C3_111*d_al1 + C3_211*d_al2)) + ch*igt12*(d2_al12 - (C3_012*d_al0 + C3_112*d_al1 + C3_212*d_al2)) + ch*igt20*(d2_al20 - (C3_020*d_al0 + C3_120*d_al1 + C3_220*d_al2)) + ch*igt21*(d2_al21 - (C3_021*d_al0 + C3_121*d_al1 + C3_221*d_al2)) + ch*igt22*(d2_al22 - (C3_022*d_al0 + C3_122*d_al1 + C3_222*d_al2));
