// === L7: RHS outputs ===
a_rhs[pp] = lambda[0]*(be0*ad_al0+be1*ad_al1+be2*ad_al2) - 2.0*al*Kv;
b_rhs0[pp] = 0.75*(lambda_f[0]+lambda_f[1]*al)*Bv0 + lambda[1]*(be0*ad_be00+be1*ad_be01+be2*ad_be02);
