b_rhs2[pp] = 0.75*(lambda_f[0]+lambda_f[1]*al)*Bv2 + lambda[1]*(be0*ad_be20+be1*ad_be21+be2*ad_be22);
gt_rhs00[pp] = be0*ad_gt000+be1*ad_gt100+be2*ad_gt200 + gt00*d_be00 + gt00*d_be00 + gt01*d_be10 + gt10*d_be10 + gt02*d_be20 + gt20*d_be20 + w_lie*gt00*div_be - 2.0*al*At00;
gt_rhs01[pp] = be0*ad_gt001+be1*ad_gt101+be2*ad_gt201 + gt00*d_be01 + gt01*d_be00 + gt01*d_be11 + gt11*d_be10 + gt02*d_be21 + gt21*d_be20 + w_lie*gt01*div_be - 2.0*al*At01;
gt_rhs02[pp] = be0*ad_gt002+be1*ad_gt102+be2*ad_gt202 + gt00*d_be02 + gt02*d_be00 + gt01*d_be12 + gt12*d_be10 + gt02*d_be22 + gt22*d_be20 + w_lie*gt02*div_be - 2.0*al*At02;
gt_rhs11[pp] = be0*ad_gt011+be1*ad_gt111+be2*ad_gt211 + gt10*d_be01 + gt01*d_be01 + gt11*d_be11 + gt11*d_be11 + gt12*d_be21 + gt21*d_be21 + w_lie*gt11*div_be - 2.0*al*At11;
gt_rhs12[pp] = be0*ad_gt012+be1*ad_gt112+be2*ad_gt212 + gt10*d_be02 + gt02*d_be01 + gt11*d_be12 + gt12*d_be11 + gt12*d_be22 + gt22*d_be21 + w_lie*gt12*div_be - 2.0*al*At12;
gt_rhs22[pp] = be0*ad_gt022+be1*ad_gt122+be2*ad_gt222 + gt20*d_be02 + gt02*d_be02 + gt21*d_be12 + gt12*d_be12 + gt22*d_be22 + gt22*d_be22 + w_lie*gt22*div_be - 2.0*al*At22;
chi_rhs[pp] = (be0*ad_ch0+be1*ad_ch1+be2*ad_ch2) + w_lie*ch*div_be + (2.0/3.0)*ch*al*Kv;
At_rhs00[pp] = (be0*ad_At000+be1*ad_At100+be2*ad_At200 + At00*d_be00 + At00*d_be00 + At01*d_be10 + At10*d_be10 + At02*d_be20 + At20*d_be20 + w_lie*At00*div_be) + ch*tf00 + al*(Kv*At00 - 2.0*AikAkj00);
At_rhs01[pp] = (be0*ad_At001+be1*ad_At101+be2*ad_At201 + At00*d_be01 + At01*d_be00 + At01*d_be11 + At11*d_be10 + At02*d_be21 + At21*d_be20 + w_lie*At01*div_be) + ch*tf01 + al*(Kv*At01 - 2.0*AikAkj01);
At_rhs02[pp] = (be0*ad_At002+be1*ad_At102+be2*ad_At202 + At00*d_be02 + At02*d_be00 + At01*d_be12 + At12*d_be10 + At02*d_be22 + At22*d_be20 + w_lie*At02*div_be) + ch*tf02 + al*(Kv*At02 - 2.0*AikAkj02);
At_rhs11[pp] = (be0*ad_At011+be1*ad_At111+be2*ad_At211 + At10*d_be01 + At01*d_be01 + At11*d_be11 + At11*d_be11 + At12*d_be21 + At21*d_be21 + w_lie*At11*div_be) + ch*tf11 + al*(Kv*At11 - 2.0*AikAkj11);
At_rhs12[pp] = (be0*ad_At012+be1*ad_At112+be2*ad_At212 + At10*d_be02 + At02*d_be01 + At11*d_be12 + At12*d_be11 + At12*d_be22 + At22*d_be21 + w_lie*At12*div_be) + ch*tf12 + al*(Kv*At12 - 2.0*AikAkj12);
At_rhs22[pp] = (be0*ad_At022+be1*ad_At122+be2*ad_At222 + At20*d_be02 + At02*d_be02 + At21*d_be12 + At12*d_be12 + At22*d_be22 + At22*d_be22 + w_lie*At22*div_be) + ch*tf22 + al*(Kv*At22 - 2.0*AikAkj22);
K_rhs[pp] = (be0*ad_K0+be1*ad_K1+be2*ad_K2) - lap_a + al*(Kv*Kv/3.0 + At_sqr);
